package com.aadil.jobtracker.security;import com.aadil.jobtracker.UserRepository.UserRepository;import com.aadil.jobtracker.entity.UserEntity;import org.springframework.security.authentication.AuthenticationManager;import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;import org.springframework.security.core.Authentication;import org.springframework.security.core.userdetails.UserDetails;import org.springframework.security.core.userdetails.UserDetailsService;import org.springframework.security.core.userdetails.UsernameNotFoundException;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Service;@Servicepublic class AuthenticationService {    private final UserRepository userRepository;    private final PasswordEncoder passwordEncoder;    private final AuthenticationManager authenticationManager;    private final JwtUtility jwtUtility;    private final UserDetailsService userDetailsService;    public AuthenticationService(UserRepository userRepository, PasswordEncoder passwordEncoder, AuthenticationManager authenticationManager, JwtUtility jwtUtility, UserDetailsService userDetailsService) {        this.userRepository = userRepository;        this.passwordEncoder = passwordEncoder;        this.authenticationManager = authenticationManager;        this.jwtUtility = jwtUtility;        this.userDetailsService = userDetailsService;    }    public void register (RequestRegisterDTO register){        if (userRepository.findByEmail(register.getEmail()).isPresent()){            throw new RuntimeException("User email is already exists");        }        if (register.getPassword()==null || register.getPassword().isBlank() || register.getPassword().length()>6){            throw new RuntimeException("Password is required and should be below 6 Characters");        }        if (register.getEmail()==null || register.getEmail().isBlank()){            throw new RuntimeException("Email is Required");        }        String hashedPassword = passwordEncoder.encode(register.getPassword());        UserEntity user = new UserEntity();        user.setName(register.getUsername());        user.setEmail(register.getEmail().trim().toLowerCase());        user.setPassword(hashedPassword);        user.setRoles(UserRoles.USER.getUserRoles());        userRepository.save(user);    }    public String login (LoginRequestDTO login){        if (login.getEmail()==null || login.getPassword()==null){            throw new RuntimeException("Email OR Password is be NULL");        }        String email = login.getEmail().trim().toLowerCase();        userRepository.findByEmail(email).orElseThrow(()->new UsernameNotFoundException("Email is NOT found"));        Authentication authentication = authenticationManager.authenticate(new UsernamePasswordAuthenticationToken(email,login.getPassword()));        if (authentication.isAuthenticated()){            System.out.println("User is Authenticated, Ready to Proceed");        }        UserDetails userDetails = userDetailsService.loadUserByUsername(email);        return jwtUtility.generateToken(userDetails);    }}